            start_business: "خطوات إنشاء عمل تجاري: 1️⃣ الفكرة والتحقق 2️⃣ بحث السوق 3️⃣ خطة العمل 4️⃣ الهيكل القانوني 5️⃣ التسجيل 6️⃣ التمويل 7️⃣ العلامة التجارية 8️⃣ التسويق 9️⃣ الإطلاق. 🚀",
            value_creation: "الجانب الرئيسي لأي عمل هو خلق القيمة. إذا قدمت شيئاً مفيداً، سيكون الناس على استعداد للدفع مقابله. 💡",
            profit: "الربح = الإيرادات − جميع التكاليف. الربح هو الهدف النهائي لكل عمل تجاري. الربح الصافي هو ما يتبقى بعد سداد جميع الضرائب. 💰",
            revenue: "الإيرادات هي إجمالي المال الذي تكسبه الشركة من مبيعاتها قبل خصم التكاليف. تُعرف أيضاً بـ 'المبيعات'. 📊",
            costs: "التكاليف هي جميع النفقات اللازمة لتشغيل الأعمال: ثابتة (إيجار، رواتب) ومتغيرة (مواد خام، شحن). التحكم في التكاليف أساسي للربحية. 💸",
            loss: "تحدث الخسارة عندما تتجاوز التكاليف الإيرادات. الحل: زيادة الإيرادات أو تخفيض التكاليف. حلل المشكلة الأكبر أولاً. 📉",
            cash_flow: "التدفق النقدي يُظهر الأموال الواردة والصادرة. يمكن أن تكون الشركة مربحة لكنها تفلس بسبب نقص السيولة. راقبه أسبوعياً! 💵",
            finance: "التمويل التجاري يشمل: إدارة الأموال، الاستثمارات، التكاليف، الإيرادات والتخطيط المالي. القاعدة المالية السليمة أساسية للنمو. 📈",
            budget: "الميزانية هي خطة مالية تُقدّر الإيرادات والمصروفات. تساعد في التحكم بالنفقات وتحقيق الأهداف. راجعها شهرياً. 📋",
            investment: "الاستثمار هو تخصيص الأموال لشيء ما بهدف تحقيق عائد أعلى. قيّم دائماً المخاطر وعائد الاستثمار قبل الاستثمار. 💰",
            risk: "المخاطرة هي احتمال خسارة الأموال. أدرها من خلال التخطيط والتنويع والتأمين المناسب. 🛡️",
            roi: "عائد الاستثمار (ROI) = (الربح − التكلفة) / التكلفة × 100%. يقيس كفاءة الاستثمار. ROI إيجابي = استثمار مربح. 📊",
            break_even: "نقطة التعادل هي عندما تساوي الإيرادات التكاليف. المعادلة: التكاليف الثابتة ÷ (السعر − التكاليف المتغيرة). استخدم الآلة الحاسبة! 🧮",
            break_even_explained: "معادلة التعادل: التكاليف الثابتة ÷ (السعر لكل وحدة − التكلفة المتغيرة لكل وحدة). مثال: 10,000 $ ÷ (20 $ − 8 $) = 833 وحدة. استخدم الآلة الحاسبة! 📊",
            entrepreneur: "رائد الأعمال هو شخص يحدد فرصة، يتحمل المخاطر ويبني عملاً تجارياً. الصفات الأساسية: رؤية، مرونة وقدرة على التنفيذ. 🚀",
            entrepreneurship: "ريادة الأعمال هي عملية إنشاء وإدارة عمل تجاري جديد مع تحمل المخاطر. إنها محرك الابتكار والنمو الاقتصادي. 🔥",
            startup: "الشركة الناشئة هي شركة حديثة ذات نمو عالٍ ونموذج عمل قابل للتوسع. تُموّل من المستثمرين ورأس المال المغامر. 🚀",
            capital: "تحتاج إلى موارد للبدء: مدخرات شخصية، قروض أو مستثمرين. ابدأ بالحد الأدنى وتحقق قبل أن تستثمر الكثير. 💰",
            profitability: "يجب أن يكون العمل مربحاً للبقاء. إذا تجاوزت النفقات دائماً الإيرادات، فهو هواية وليس عملاً. 📈",
